import requests
import json

def get_wikipedia_revisions(title, start_date, end_date):
    url = "https://en.wikipedia.org/w/api.php"

    headers = {
        'User-Agent': 'WikipediaBot/1.0 (https://example.com/contact)'
    }

    params = {
        'action': 'query',
        'format': 'json',
        'titles': title,
        'prop': 'revisions',
        'rvstart': end_date,
        'rvend': start_date,
        'rvlimit': 10,
        'rvprop': 'timestamp|ids'
    }

    response = requests.get(url, params=params, headers=headers)

    if response.status_code == 200:
        return response.json()
    else:
        print(f"Error {response.status_code}: {response.text}")
        return None

